import pytest
import requests

BASE_URL = "<base_url_fixture>"

@pytest.fixture
def registered_device_headers():
    return <get_device_cert_headers>("dev-001")

@pytest.fixture(autouse=True)
def cleanup_observation():
    yield
    <delete_observation_if_exists>("obs-ep-001")

def test_registered_device_ingest_valid_observation(registered_device_headers):
    payload = {
        "resourceType": "Observation",
        "id": "obs-ep-001",
        "status": "final",
        "code": {
            "coding": [{"system": "http://loinc.org", "code": "8867-4"}]
        },
        "subject": {"reference": "Patient/pat-001"},
        "valueQuantity": {"value": 72, "unit": "bpm"}
    }
    resp = requests.post(
        f"{BASE_URL}/Ingest",
        json=payload,
        headers=registered_device_headers,
        timeout=10
    )
