import pytest
import requests

BASE_URL = "<base_url_fixture>"

@pytest.fixture
def registered_device_headers():
    return <get_device_cert_headers>("dev-001")

def test_missing_mandatory_element_rejected(registered_device_headers):
    payload = {
        "resourceType": "Observation",
        "id": "obs-dt-nocode",
        "status": "final",
        "subject": {"reference": "Patient/pat-001"},
        "valueQuantity": {"value": 60, "unit": "bpm"}
    }
    resp = requests.post(
        f"{BASE_URL}/Ingest",
        json=payload,
        headers=registered_device_headers,
        timeout=10
    )
    assert resp.status_code in (400, 422)
    body = resp.json()
    assert body.get("resourceType") == "OperationOutcome"
    issues = body.get("issue", [])
    assert any("code" in str(i).lower() for i in issues)
    assert not <observation_exists>("obs-dt-nocode")

import pytest
import requests

BASE_URL = "<base_url_fixture>"

@pytest.fixture
def registered_device_headers():
    return <get_device_cert_headers>("dev-001")

@pytest.fixture(autouse=True)
def seed_final_observation(registered_device_headers):
    <ensure_observation_exists>("obs-stc-001", status="final", headers=registered_device_headers)
    yield
    <delete_observation_if_exists>("obs-stc-001")

def test_conflicting_state_transition_rejected(registered_device_headers):
    payload = {
        "resourceType": "Observation",
        "id": "obs-stc-001",
        "status": "preliminary",
        "code": {
            "coding": [{"system": "http://loinc.org", "code": "8867-4"}]
        },
        "subject": {"reference": "Patient/pat-001"},
        "valueQuantity": {"value": 80, "unit": "bpm"}
    }
    resp = requests.post(
        f"{BASE_URL}/Ingest",
        json=payload,
        headers=registered_device_headers,
        timeout=10
    )
    assert resp.status_code in (409, 422)
    body = resp.json()
    assert body.get("resourceType") == "OperationOutcome"
    stored = <get_observation>("obs-stc-001", headers=registered_device_headers)
    assert stored.get("status") == "final", "Stored Observation must retain final status"

